// ============================================================
// Filtrer les sessions éligibles au suivi à froid
// ============================================================
// Critères :
//   - date_fin + 180 jours dépassé (6 mois)
//   - suivi_froid_envoye !== TRUE (pas encore envoyé)
// ============================================================

const sessions = $input.all().map(item => item.json);
const now = new Date();
const DELAI_JOURS = 180;

const eligibles = sessions.filter(s => {
  if (s.suivi_froid_envoye === 'TRUE' || s.suivi_froid_envoye === true) return false;
  if (!s.date_fin) return false;

  const dateFin = new Date(s.date_fin);
  const diffJours = Math.floor((now - dateFin) / (1000 * 60 * 60 * 24));
  return diffJours >= DELAI_JOURS;
});

if (eligibles.length === 0) {
  return [{ json: { _empty: true } }];
}

return eligibles.map(s => ({ json: { ...s, jours_depuis_fin: Math.floor((now - new Date(s.date_fin)) / (1000 * 60 * 60 * 24)) } }));

// ============================================================
// Construire l'URL pré-remplie du Google Form Suivi à Froid
// ============================================================

const inscrit = $json;
const session = $('Sessions éligibles').item.json;
const formation = $('Lire Formation').item.json;

const formId = '1h63PHGz4mTa-4NnY8Na-VUC8lN4jMLNnR9b3Jm-1Twc';

const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform`;
const params = new URLSearchParams({
  'entry.inscription_id': inscrit.inscription_id || '',
  'entry.session_id': session.session_id || '',
  'entry.apprenant_nom': inscrit.nom || '',
  'entry.apprenant_prenom': inscrit.prenom || ''
});

const url = `${baseUrl}?${params.toString()}`;

return [{
  json: {
    ...inscrit,
    url_suivi_froid: url,
    session_id: session.session_id,
    formation_intitule: formation.intitule || '',
    date_debut: session.date_debut || '',
    date_fin: session.date_fin || ''
  }
}];

// ============================================================
// Préparer le HTML de l'attestation de formation
// ============================================================
// Lit le template templates/template_attestation.html depuis le
// filesystem n8n et remplace les placeholders {{variable}}.
// Le fichier HTML n'est PAS embarqué dans ce workflow.
// ============================================================

const fs = require('fs');
const templatePath = '/data/templates/template_attestation.html';
let html = fs.readFileSync(templatePath, 'utf8');

const inscrit = $('Construire URL Suivi Froid').item.json;
const session = $('Sessions éligibles').item.json;
const formation = $('Lire Formation').item.json;
const organisme = $('Lire Organisme').item.json;

const replacements = {
  'organisme_nom': organisme.nom || '',
  'organisme_adresse': organisme.adresse || '',
  'organisme_siret': organisme.siret || '',
  'organisme_nda': organisme.nda || '',
  'organisme_representant': organisme.representant || organisme.responsable_qualite || '',
  'apprenant_nom': inscrit.nom || '',
  'apprenant_prenom': inscrit.prenom || '',
  'formation_intitule': formation.intitule || '',
  'formation_duree': formation.duree_heures || '',
  'formation_objectifs': formation.objectifs || '',
  'session_id': session.session_id || '',
  'date_debut': session.date_debut || '',
  'date_fin': session.date_fin || '',
  'lieu': session.lieu || '',
  'date_generation': new Date().toLocaleDateString('fr-FR')
};

for (const [key, value] of Object.entries(replacements)) {
  html = html.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value);
}

return [{
  json: {
    html_attestation: html,
    nom_fichier_attestation: `Attestation_${session.session_id}_${inscrit.nom}_${inscrit.prenom}.pdf`,
    inscrit_email: inscrit.email || '',
    inscrit_prenom: inscrit.prenom || '',
    inscrit_nom: inscrit.nom || '',
    formation_intitule: formation.intitule || '',
    session_id: session.session_id || ''
  }
}];

// ============================================================
// Préparer le HTML du certificat de réalisation
// ============================================================
// Lit le template templates/template_certificat_realisation.html
// depuis le filesystem n8n et remplace les placeholders.
// Le fichier HTML n'est PAS embarqué dans ce workflow.
// ============================================================

const fs = require('fs');
const templatePath = '/data/templates/template_certificat_realisation.html';
let html = fs.readFileSync(templatePath, 'utf8');

const attestationData = $('Préparer Attestation').item.json;
const session = $('Sessions éligibles').item.json;
const formation = $('Lire Formation').item.json;
const organisme = $('Lire Organisme').item.json;
const inscrit = $('Construire URL Suivi Froid').item.json;

const replacements = {
  'organisme_nom': organisme.nom || '',
  'organisme_adresse': organisme.adresse || '',
  'organisme_siret': organisme.siret || '',
  'organisme_nda': organisme.nda || '',
  'organisme_representant': organisme.representant || organisme.responsable_qualite || '',
  'apprenant_nom': inscrit.nom || '',
  'apprenant_prenom': inscrit.prenom || '',
  'formation_intitule': formation.intitule || '',
  'formation_duree': formation.duree_heures || '',
  'session_id': session.session_id || '',
  'date_debut': session.date_debut || '',
  'date_fin': session.date_fin || '',
  'lieu': session.lieu || '',
  'nb_heures_realisees': session.nb_heures_realisees || formation.duree_heures || '',
  'date_generation': new Date().toLocaleDateString('fr-FR')
};

for (const [key, value] of Object.entries(replacements)) {
  html = html.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value);
}

return [{
  json: {
    html_certificat: html,
    nom_fichier_certificat: `Certificat_realisation_${session.session_id}_${inscrit.nom}_${inscrit.prenom}.pdf`,
    inscrit_email: inscrit.email || '',
    inscrit_prenom: inscrit.prenom || '',
    inscrit_nom: inscrit.nom || '',
    formation_intitule: formation.intitule || '',
    nom_fichier_attestation: attestationData.nom_fichier_attestation
  }
}];
